const breakpoints = function () {
    "use strict";
    let list = null;
    const media = {};
    const events = [];

    const init = function (breakpointsList) {
        list = breakpointsList;
        window.addEventListener("resize", poll);
        window.addEventListener("orientationchange", poll);
        window.addEventListener("load", poll);
        window.addEventListener("fullscreenchange", poll);
    };

    const active = function (breakpoint) {
        if (!(breakpoint in media)) {
            let operator = "eq";
            let value = breakpoint;
            if (breakpoint.startsWith(">=")) {
                operator = "gte";
                value = breakpoint.substr(2);
            } else if (breakpoint.startsWith("<=")) {
                operator = "lte";
                value = breakpoint.substr(2);
            } else if (breakpoint.startsWith(">")) {
                operator = "gt";
                value = breakpoint.substr(1);
            } else if (breakpoint.startsWith("<")) {
                operator = "lt";
                value = breakpoint.substr(1);
            } else if (breakpoint.startsWith("!")) {
                operator = "not";
                value = breakpoint.substr(1);
            }

            if (value && value in list) {
                let mediaQuery = "";
                const dimensions = list[value];
                if (Array.isArray(dimensions)) {
                    const min = parseInt(dimensions[0]);
                    const max = parseInt(dimensions[1]);
                    if (isNaN(min)) {
                        if (isNaN(max)) {
                            return;
                        }
                        const unit = dimensions[1].substr(String(max).length);
                        switch (operator) {
                            case "gte":
                                mediaQuery = `screen`;
                                break;
                            case "lte":
                                mediaQuery = `screen and (max-width: ${max}${unit})`;
                                break;
                            case "gt":
                                mediaQuery = `screen and (min-width: ${max + 1}${unit})`;
                                break;
                            case "lt":
                                mediaQuery = `screen and (max-width: -1px)`;
                                break;
                            case "not":
                                mediaQuery = `screen and (min-width: ${max + 1}${unit})`;
                                break;
                            default:
                                mediaQuery = `screen and (max-width: ${max}${unit})`;
                        }
                    } else if (isNaN(max)) {
                        const unit = dimensions[0].substr(String(min).length);
                        switch (operator) {
                            case "gte":
                                mediaQuery = `screen and (min-width: ${min}${unit})`;
                                break;
                            case "lte":
                                mediaQuery = `screen`;
                                break;
                            case "gt":
                                mediaQuery = `screen and (max-width: -1px)`;
                                break;
                            case "lt":
                                mediaQuery = `screen and (max-width: ${min - 1}${unit})`;
                                break;
                            case "not":
                                mediaQuery = `screen and (max-width: ${min - 1}${unit})`;
                                break;
                            default:
                                mediaQuery = `screen and (min-width: ${min}${unit})`;
                        }
                    } else {
                        const minUnit = dimensions[0].substr(String(min).length);
                        const maxUnit = dimensions[1].substr(String(max).length);
                        if (minUnit !== maxUnit) {
                            return;
                        }
                        switch (operator) {
                            case "gte":
                                mediaQuery = `screen and (min-width: ${min}${minUnit})`;
                                break;
                            case "lte":
                                mediaQuery = `screen and (max-width: ${max}${maxUnit})`;
                                break;
                            case "gt":
                                mediaQuery = `screen and (min-width: ${max + 1}${maxUnit})`;
                                break;
                            case "lt":
                                mediaQuery = `screen and (max-width: ${min - 1}${minUnit})`;
                                break;
                            case "not":
                                mediaQuery = `screen and (max-width: ${min - 1}${minUnit}), screen and (min-width: ${max + 1}${maxUnit})`;
                                break;
                            default:
                                mediaQuery = `screen and (min-width: ${min}${minUnit}) and (max-width: ${max}${maxUnit})`;
                        }
                    }
                } else {
                    mediaQuery = dimensions.startsWith("(") ? `screen and ${dimensions}` : dimensions;
                }
                media[breakpoint] = mediaQuery;
            } else {
                media[breakpoint] = false;
            }
        }
        return media[breakpoint] && window.matchMedia(media[breakpoint]).matches;
    };

    const on = function (breakpoint, handler) {
        events.push({ query: breakpoint, handler, state: false });
        active(breakpoint) && handler();
    };

    const poll = function () {
        for (let i = 0; i < events.length; i++) {
            const event = events[i];
            active(event.query) ? event.state || (event.state = true, event.handler()) : event.state && (event.state = false);
        }
    };

    return {
        init,
        on
    };
}();

